CREATE OR REPLACE FUNCTION OFSERM.CS_Minority_Interest_Surplus_Capital(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    MERGE  INTO FSI_MINORITY_INTEREST TT USING (   SELECT * FROM (  SELECT  /*+ PARALLEL(4) */ FSI_MINORITY_INTEREST.N_ENTITY_SKEY,FSI_MINORITY_INTEREST.N_GAAP_SKEY,FSI_MINORITY_INTEREST.N_RUN_SKEY,FSI_MINORITY_INTEREST.N_MIS_DATE_SKEY,FSI_MINORITY_INTEREST.N_FORECAST_DATE_SKEY,(FSI_MINORITY_INTEREST.N_MIN_REQ_AT1_CAPITAL) AS  T_1529392731772_0,   (CASE  WHEN  ( ((1=1)) ) THEN 10 ELSE 11 END)  AS COND_1529392731772_10 ,  (CASE WHEN 1 = 1 THEN FSI_MINORITY_INTEREST.n_min_required_tier1_capital ELSE NULL END -CASE WHEN 1 = 1 THEN FSI_MINORITY_INTEREST.n_min_req_cet1_capital ELSE NULL END ) AS EXP_1529392731772_10,(FSI_MINORITY_INTEREST.N_MIN_REQ_AT1_CAPITAL) AS EXP_1529392731772_11 ,(FSI_MINORITY_INTEREST.N_MIN_REQ_T2_CAPITAL) AS  T_1529392731772_1,   (CASE  WHEN  ( ((1=1)) ) THEN 20 ELSE 21 END)  AS COND_1529392731772_20 ,  (CASE WHEN 1 = 1 THEN FSI_MINORITY_INTEREST.n_min_req_total_capital ELSE NULL END  - CASE WHEN 1 = 1 THEN FSI_MINORITY_INTEREST.n_min_required_tier1_capital ELSE NULL END  ) AS EXP_1529392731772_20,(FSI_MINORITY_INTEREST.N_MIN_REQ_T2_CAPITAL) AS EXP_1529392731772_21 ,(FSI_MINORITY_INTEREST.N_MI_SURPLUS_AMOUNT_CET1) AS  T_1529392731772_2,   (CASE  WHEN  ( ((1=1)) ) THEN 30 ELSE 31 END)  AS COND_1529392731772_30 ,  (CASE WHEN COALESCE(CASE WHEN 1 = 1 THEN FSI_MINORITY_INTEREST.n_common_equity_tier1_amount ELSE NULL END ,0) < COALESCE(CASE WHEN 1 = 1 THEN FSI_MINORITY_INTEREST.n_min_req_cet1_capital ELSE NULL END ,0) THEN 0 ELSE COALESCE(CASE WHEN 1 = 1 THEN FSI_MINORITY_INTEREST.n_common_equity_tier1_amount ELSE NULL END ,0) - COALESCE(CASE WHEN 1 = 1 THEN FSI_MINORITY_INTEREST.n_min_req_cet1_capital ELSE NULL END ,0) END) AS EXP_1529392731772_30,(FSI_MINORITY_INTEREST.N_MI_SURPLUS_AMOUNT_CET1) AS EXP_1529392731772_31 ,(FSI_MINORITY_INTEREST.N_MI_SURPLUS_TIER1_AMOUNT) AS  T_1529392731772_3,   (CASE  WHEN  ( ((1=1)) ) THEN 40 ELSE 41 END)  AS COND_1529392731772_40 ,  (CASE WHEN 1 = 1 THEN FSI_MINORITY_INTEREST.n_tier1_amount ELSE NULL END  - CASE WHEN 1 = 1 THEN FSI_MINORITY_INTEREST.n_min_required_tier1_capital ELSE NULL END  ) AS EXP_1529392731772_40,(FSI_MINORITY_INTEREST.N_MI_SURPLUS_TIER1_AMOUNT) AS EXP_1529392731772_41 ,(FSI_MINORITY_INTEREST.N_MI_SURPLUS_TOTAL_CAPITAL) AS  T_1529392731772_4,   (CASE  WHEN  ( ((1=1)) ) THEN 50 ELSE 51 END)  AS COND_1529392731772_50 ,  (CASE WHEN 1 = 1 THEN FSI_MINORITY_INTEREST.n_total_capital_amount ELSE NULL END  - CASE WHEN 1 = 1 THEN FSI_MINORITY_INTEREST.n_min_req_total_capital ELSE NULL END ) AS EXP_1529392731772_50,(FSI_MINORITY_INTEREST.N_MI_SURPLUS_TOTAL_CAPITAL) AS EXP_1529392731772_51  FROM  FSI_MINORITY_INTEREST LEFT OUTER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = FSI_MINORITY_INTEREST.N_RUN_SKEY LEFT OUTER JOIN DIM_DATES ON DIM_DATES.N_DATE_SKEY = FSI_MINORITY_INTEREST.N_MIS_DATE_SKEY LEFT OUTER JOIN DIM_GAAP ON DIM_GAAP.N_GAAP_SKEY = FSI_MINORITY_INTEREST.N_GAAP_SKEY LEFT OUTER JOIN FCT_ENTITY_INFO ON FCT_ENTITY_INFO.N_ENTITY_SKEY = FSI_MINORITY_INTEREST.N_ENTITY_SKEY AND FCT_ENTITY_INFO.N_MIS_DATE_SKEY = FSI_MINORITY_INTEREST.N_MIS_DATE_SKEY AND FCT_ENTITY_INFO.N_RUN_SKEY = FSI_MINORITY_INTEREST.N_RUN_SKEY AND FCT_ENTITY_INFO.N_GAAP_SKEY = FSI_MINORITY_INTEREST.N_GAAP_SKEY AND FCT_ENTITY_INFO.N_FORECAST_DATE_SKEY = FSI_MINORITY_INTEREST.N_FORECAST_DATE_SKEY   WHERE (1=1)  AND (DIM_RUN.N_RUN_SKEY = '870' AND DIM_DATES.d_calendar_date = TO_DATE('20260331','yyyymmdd'))  ) WHERE (   (COND_1529392731772_10 <> 11)   OR  (COND_1529392731772_20 <> 21)  OR  (COND_1529392731772_30 <> 31)  OR  (COND_1529392731772_40 <> 41)  OR  (COND_1529392731772_50 <> 51) ) ) SS ON ( TT.N_ENTITY_SKEY= SS.N_ENTITY_SKEY AND TT.N_GAAP_SKEY= SS.N_GAAP_SKEY AND TT.N_RUN_SKEY= SS.N_RUN_SKEY AND TT.N_MIS_DATE_SKEY= SS.N_MIS_DATE_SKEY AND TT.N_FORECAST_DATE_SKEY= SS.N_FORECAST_DATE_SKEY) WHEN MATCHED THEN UPDATE SET  TT.N_MIN_REQ_AT1_CAPITAL=  CASE  WHEN  COND_1529392731772_10=10 THEN EXP_1529392731772_10 ELSE EXP_1529392731772_11 END  , TT.N_MIN_REQ_T2_CAPITAL=  CASE  WHEN  COND_1529392731772_20=20 THEN EXP_1529392731772_20 ELSE EXP_1529392731772_21 END  , TT.N_MI_SURPLUS_AMOUNT_CET1=  CASE  WHEN  COND_1529392731772_30=30 THEN EXP_1529392731772_30 ELSE EXP_1529392731772_31 END  , TT.N_MI_SURPLUS_TIER1_AMOUNT=  CASE  WHEN  COND_1529392731772_40=40 THEN EXP_1529392731772_40 ELSE EXP_1529392731772_41 END  , TT.N_MI_SURPLUS_TOTAL_CAPITAL=  CASE  WHEN  COND_1529392731772_50=50 THEN EXP_1529392731772_50 ELSE EXP_1529392731772_51 END;

    COMMIT;
    RETURN 'OK';

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        RETURN 'FAIL: ' || SQLERRM;
END;
